// // This comment suggests that the output X will be HIGH only when fewer than three of the four input signals (A1, A2, A3, A4) are HIGH or when exactly one of these inputs is HIGH alongside the additional input B1.
module top_module(
    X ,
    A1,
    A2,
    A3,
    A4,
    B1
);output X ;
    input  A1;
    input  A2;
    input  A3;
    input  A4;
    input  B1;

    // Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    assign X = ((A1&A2&A3) | (A1&A2&A4) | (A1&A3&A4) | (A2&A3&A4) | (A1&A2&B1) | (A1&A3&B1) | (A1&A4&B1) | (A2&A3&B1) | (A2&A4&B1) | (A3&A4&B1));

endmodule
